import React from "react";

export const VideoCard = ({ video, onSelect }) => {
  // Function to extract YouTube video ID from URL
  const getYouTubeVideoId = (url) => {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  // Function to generate YouTube thumbnail URL
  const getYouTubeThumbnail = (url) => {
    const videoId = getYouTubeVideoId(url);
    if (videoId) {
      return `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`;
    }
    return video.thumbnail || '/img/placeholder-video.jpg'; // Fallback
  };

  const handleVideoClick = () => {
    if (onSelect) {
      onSelect();
    } else {
      window.open(video.youtubeUrl, '_blank');
    }
  };

  return (
    <div className="video-card" onClick={handleVideoClick}>
      <div className="video-thumbnail">
        <img src={getYouTubeThumbnail(video.youtubeUrl)} alt={video.title} />
        <div className="play-button">
          <i className="fa fa-play"></i>
        </div>
        <div className="video-overlay">
          <h3 className="video-title">{video.title}</h3>
          <p className="video-subtitle">NEW OFFICIAL TRAILER</p>
        </div>
      </div>
      <div className="video-content">
        <h4>{video.title}</h4>
        <div className="video-separator"></div>
        <p className="video-description">{video.description}</p>
        <button className="choose-video-btn">Choose This Video</button>
      </div>
    </div>
  );
};
